export const checkId = 'cors';
export const name = 'CORS Configured';
export const appliesTo = ['deployable', 'server', 'framework'];

const BACKEND_DEPS = ['express', 'fastify', 'koa', 'hono', 'elysia', 'hapi', 'sails', 'meteor', 'feathers', 'restify', 'polka', 'micro', 'connect', 'restana', '0http'];
const CONTENT_FRAMEWORKS = ['next', 'nuxt', 'gatsby', 'astro', 'hexo', 'vuepress', 'vitepress', 'docusaurus', 'eleventy'];

const EXCLUDED_PATH_RX = /(^|\/)(node_modules|\.git|\.next|out|dist|build|coverage|\.tmp|test|tests|__tests__|spec|specs|example|examples|demo|demos|fixtures|fixture|mock|mocks|docs|playground|storybook|e2e|cypress|vitest|jest|benchmark|benchmarks|perf)\//i;
const EXCLUDED_FILE_RX = /\.(test|spec|e2e|cy|stories)\.(js|ts|jsx|tsx|mjs|cjs|mts|cts)$/i;

const CORS_PATTERNS = [
  /require\s*\(\s*['"][^'"]*cors['"]\s*\)/,
  /import\s+.*?['"][^'"]*cors['"]/,
  /from\s+['"][^'"]*cors['"]/,
  /access-control-allow-origin/i,
  /access-control-allow-methods/i,
  /access-control-allow-headers/i,
  /access-control-allow-credentials/i,
  /access-control-expose-headers/i,
  /access-control-max-age/i,
  /access-control-request/i,
  /cors\s*:\s*(true|\{)/i,
  /\bcors\s*\(/i,
  /enableCors/i,
  /allowedOrigins?/i,
  /allowOrigin/i,
  /corsOrigins?/i,
  /use\s*\(\s*cors/i,
  /register\s*\([^)]*cors/i,
  /corsHandler/i,
  /handleCors/i,
  /withCors/i,
  /setHeader\s*\(\s*['"]Access-Control/i,
  /headers\s*:\s*\[/i,
  /origin\s*:\s*(\[|['"`]|https?:\/\/|\*)/i,
];

const BACKEND_IMPORT_PATTERNS = [
  /require\s*\(\s*['"]express['"]\s*\)/,
  /from\s+['"]express['"]/,
  /require\s*\(\s*['"]fastify['"]\s*\)/,
  /from\s+['"]fastify['"]/,
  /require\s*\(\s*['"]koa['"]\s*\)/,
  /from\s+['"]koa['"]/,
  /require\s*\(\s*['"]hono['"]\s*\)/,
  /from\s+['"]hono['"]/,
  /require\s*\(\s*['"]@hapi\/hapi['"]\s*\)/,
  /from\s+['"]@hapi\/hapi['"]/,
  /require\s*\(\s*['"]restify['"]\s*\)/,
  /from\s+['"]restify['"]/,
  /require\s*\(\s*['"]connect['"]\s*\)/,
  /from\s+['"]connect['"]/,
  /require\s*\(\s*['"]polka['"]\s*\)/,
  /from\s+['"]polka['"]/,
  /require\s*\(\s*['"]@fastify\/fastify['"]\s*\)/,
  /from\s+['"]@fastify\/fastify['"]/,
  /require\s*\(\s*['"]@hono\/node-server['"]\s*\)/,
  /from\s+['"]@hono\/node-server['"]/,
  /require\s*\(\s*['"]elysia['"]\s*\)/,
  /from\s+['"]elysia['"]/,
  /=\s*express\s*\(\s*\)/,
  /=\s*fastify\s*\(\s*\)/,
  /new\s+Koa\b/,
  /=\s*new\s+Hono\b/,
  /restify\s*\.\s*createServer/,
];

const SERVER_FILE_RX = /(^|\/)((src|lib|app|server|api|apis|routes|routers|controllers|handlers|endpoints|middleware|webhooks|hooks|gateways|workers|services|packages|apps|cmd|bin)\/)?[^/]*(server|app|listen|index|main|worker|api|route|router|graphql|trpc|rest|webhook|hook|gateway|proxy|middleware|handler|cors)[^/]*\.(js|ts|jsx|tsx|mjs|cjs|mts|cts)$/i;
const API_ROUTE_RX = /\/(api|apis|rest|graphql|trpc|rpc|webhook|webhooks|hooks)\/[^/]+\.(js|ts|jsx|tsx|mjs|cjs|mts|cts)$/i;
const CONFIG_FILE_RX = /(^|\/)((next|nuxt|astro|gatsby|svelte)\.config\.[^/]*|vercel\.json|netlify\.toml|_headers|wrangler\.toml|fly\.toml|render\.yaml|app\.yaml|serverless\.yml|firebase\.json|worker\.toml|remix\.config\.[^/]*|blitz\.config\.[^/]*|redwood\.toml)$/i;
const INFRA_FILE_RX = /^(vercel\.json|netlify\.toml|_headers|wrangler\.toml|fly\.toml|render\.yaml|app\.yaml|serverless\.yml|firebase\.json|worker\.toml)$/i;

function isRelevantPath(p) {
  if (/(^|\/)node_modules\//.test(p)) return false;
  if (EXCLUDED_PATH_RX.test(p)) return false;
  if (EXCLUDED_FILE_RX.test(p)) return false;
  return true;
}

function hasProductionBackendDeps(pkg) {
  if (!pkg) return false;
  const deps = { ...(pkg.dependencies || {}), ...(pkg.peerDependencies || {}) };
  return BACKEND_DEPS.some(d => deps[d]);
}

function hasAnyBackendDeps(pkg) {
  if (!pkg) return false;
  const deps = { ...(pkg.dependencies || {}), ...(pkg.devDependencies || {}), ...(pkg.peerDependencies || {}) };
  return BACKEND_DEPS.some(d => deps[d]);
}

function isTutorial(pkg) {
  if (!pkg) return false;
  const text = [pkg.name, pkg.description, ...(pkg.keywords || [])].filter(Boolean).join(' ').toLowerCase();
  return /\b(learn|learning|tutorial|tutorials|course|workshop|starter[- ]?kit|boilerplate|getting[- ]?started|how[- ]?to|walkthrough|training|teach|courseware|cheatsheet|introduction)\b/.test(text);
}

function isLibraryOrFramework(pkg, tree) {
  if (!pkg) return false;
  if (hasAnyBackendDeps(pkg)) return false;
  const keywords = (pkg.keywords || []).map(k => k.toLowerCase());
  const scripts = pkg.scripts || {};
  const hasServerScript = !!(scripts.start || scripts.serve || scripts['start:prod'] || scripts.preview || scripts.server || scripts.dev);
  const libKeywords = new Set(['library', 'framework', 'middleware', 'plugin', 'toolkit', 'sdk', 'module', 'util', 'utils', 'tool', 'bundler', 'compiler', 'build-tool', 'router', 'client', 'component', 'components', 'ui', 'functional', 'helper', 'helpers', 'package', 'transform', 'loader', 'preset']);
  const hasLibKeyword = keywords.some(k => libKeywords.has(k));
  const hasMain = !!(pkg.main || pkg.module || pkg.exports || pkg.typings || pkg.types);
  const hasVersion = !!pkg.version;
  const hasPeerDeps = !!(pkg.peerDependencies && Object.keys(pkg.peerDependencies).length > 0);
  const hasPackagesDir = tree.some(p => /^packages\/[^/]+(?:\/|$)/.test(p));
  const hasAppsDir = tree.some(p => /^(apps|services|clients|web|www|site|sites|server|api|studio|dashboard|admin|portal|frontend|backend|workers|edge-functions)\/[^/]+(?:\/|$)/.test(p));
  const hasExamplesDir = tree.some(p => /^examples\/[^/]+(?:\/|$)/.test(p));
  const hasTestDir = tree.some(p => /^(test|tests|__tests__|spec|specs)\/[^/]+(?:\/|$)/.test(p));
  if (pkg.private === true && hasPackagesDir && !hasAppsDir && !hasServerScript) return true;
  if ((pkg.workspaces || tree.some(p => /^pnpm-workspace\.yaml$/.test(p))) && !hasServerScript && !hasAppsDir) return true;
  if (hasMain && hasVersion && !hasServerScript && (hasLibKeyword || hasPeerDeps || hasExamplesDir)) return true;
  if (hasExamplesDir && hasTestDir && !hasServerScript && !hasAppsDir) return true;
  return false;
}

function isStaticContentSite(pkg, tree) {
  if (!pkg) return false;
  if (hasAnyBackendDeps(pkg)) return false;
  const allDeps = { ...(pkg.dependencies || {}), ...(pkg.devDependencies || {}) };
  const hasContentFramework = CONTENT_FRAMEWORKS.some(f => allDeps[f]);
  const hasApiRoutes = tree.some(p => API_ROUTE_RX.test(p) && isRelevantPath(p));
  const hasServerEntry = tree.some(p => /(^|\/)((src|lib|bin|cmd|apps|services|packages)\/)?(server|app|listen|index|main|worker)\.(js|ts|mjs|cjs|mts|cts)$/.test(p) && isRelevantPath(p));
  if (hasContentFramework && !hasApiRoutes && !hasServerEntry) return true;
  const contentFiles = tree.filter(p => /\.(md|mdx|html|css|scss|sass|less|styl)$/.test(p) && isRelevantPath(p)).length;
  const sourceFiles = tree.filter(p => /\.(js|ts|jsx|tsx|mjs|cjs|mts|cts)$/.test(p) && isRelevantPath(p)).length;
  if (sourceFiles === 0 && contentFiles > 5) return true;
  if (contentFiles > sourceFiles * 4 && !hasApiRoutes && !hasServerEntry) return true;
  return false;
}

async function findCorsInPackageJsons(tree, files) {
  const pkgs = tree.filter(p => /(^|\/)package\.json$/.test(p) && isRelevantPath(p));
  for (const p of pkgs) {
    const content = await files.get(p);
    if (!content) continue;
    try {
      const pkg = JSON.parse(content);
      const allDeps = { ...(pkg.dependencies || {}), ...(pkg.devDependencies || {}), ...(pkg.peerDependencies || {}), ...(pkg.optionalDependencies || {}) };
      if (allDeps.cors || allDeps['@fastify/cors'] || allDeps['@koa/cors'] || allDeps['koa-cors'] || allDeps['corser'] || allDeps['kcors']) {
        return p;
      }
    } catch {}
  }
  return null;
}

async function findCorsInConfigFiles(tree, files) {
  const configs = tree.filter(p => CONFIG_FILE_RX.test(p) && isRelevantPath(p));
  for (const p of configs) {
    const content = await files.get(p);
    if (!content) continue;
    if (/cors/i.test(content) || /access-control/i.test(content)) return p;
  }
  return null;
}

async function findCorsInCodeFiles(tree, files) {
  let candidates = tree.filter(p => isRelevantPath(p) && /\.(js|ts|jsx|tsx|mjs|cjs|mts|cts)$/.test(p) && SERVER_FILE_RX.test(p));
  candidates = candidates.slice(0, 120);
  if (!candidates.length) {
    const allCode = tree.filter(p => isRelevantPath(p) && /\.(js|ts|jsx|tsx|mjs|cjs|mts|cts)$/.test(p));
    candidates = allCode.slice(0, 80);
  }
  for (const p of candidates) {
    const content = await files.get(p);
    if (!content) continue;
    for (const pat of CORS_PATTERNS) {
      if (pat.test(content)) return p;
    }
  }
  return null;
}

async function findBackendFrameworkFile(tree, files) {
  const candidates = tree.filter(p => isRelevantPath(p) && /\.(js|ts|jsx|tsx|mjs|cjs|mts|cts)$/.test(p) && SERVER_FILE_RX.test(p)).slice(0, 120);
  for (const p of candidates) {
    const content = await files.get(p);
    if (!content) continue;
    for (const pat of BACKEND_IMPORT_PATTERNS) {
      if (pat.test(content)) return p;
    }
  }
  return null;
}

export async function check(context) {
  const { tree, files, packageJson } = context;

  try {
    if (!tree || tree.length === 0) {
      return { checkId, status: 'not-applicable', confidence: 'high', message: 'Empty repository', findings: [] };
    }

    const corsPkg = await findCorsInPackageJsons(tree, files);
    if (corsPkg) {
      return { checkId, status: 'pass', confidence: 'high', message: `CORS dependency found in ${corsPkg}`, findings: [{ file: corsPkg, issue: 'cors dependency detected' }] };
    }

    const corsConfig = await findCorsInConfigFiles(tree, files);
    if (corsConfig) {
      return { checkId, status: 'pass', confidence: 'high', message: `CORS configuration found in ${corsConfig}`, findings: [{ file: corsConfig, issue: 'CORS detected' }] };
    }

    const corsCode = await findCorsInCodeFiles(tree, files);
    if (corsCode) {
      return { checkId, status: 'pass', confidence: 'high', message: `CORS configuration found in ${corsCode}`, findings: [{ file: corsCode, issue: 'CORS detected' }] };
    }

    const backendFile = await findBackendFrameworkFile(tree, files);

    const prodDeps = { ...(packageJson?.dependencies || {}), ...(packageJson?.peerDependencies || {}) };
    const hasProdBackend = BACKEND_DEPS.some(d => prodDeps[d]);

    const hasApiRoutes = tree.some(p => API_ROUTE_RX.test(p) && isRelevantPath(p));

    const scripts = packageJson?.scripts || {};
    const hasServerScript = ['start', 'serve', 'start:prod', 'preview', 'server', 'api', 'backend'].some(s => scripts[s]);

    const hasInfra = tree.some(p => INFRA_FILE_RX.test(p));

    if (hasProdBackend || hasApiRoutes || hasServerScript || backendFile || hasInfra) {
      if (isLibraryOrFramework(packageJson, tree)) {
        return { checkId, status: 'not-applicable', confidence: 'high', message: 'Library or framework source — CORS not applicable', findings: [] };
      }

      const message = backendFile
        ? `Backend framework usage detected in ${backendFile} without visible CORS configuration`
        : hasProdBackend
        ? 'Backend server dependency found without visible CORS configuration'
        : hasApiRoutes
        ? 'API routes detected without visible CORS configuration'
        : hasServerScript
        ? 'Server script detected without visible CORS configuration'
        : 'Deployment infrastructure detected without visible CORS configuration';

      return {
        checkId,
        status: 'check-it',
        confidence: backendFile || hasProdBackend || hasApiRoutes ? 'medium' : 'low',
        message,
        findings: [{ file: backendFile || 'package.json', issue: 'Verify CORS is configured for this service' }],
      };
    }

    if (isTutorial(packageJson)) {
      return { checkId, status: 'not-applicable', confidence: 'high', message: 'Tutorial or example repository — CORS not applicable', findings: [] };
    }

    if (isLibraryOrFramework(packageJson, tree)) {
      return { checkId, status: 'not-applicable', confidence: 'high', message: 'Library or framework source — CORS not applicable', findings: [] };
    }

    if (isStaticContentSite(packageJson, tree)) {
      return { checkId, status: 'not-applicable', confidence: 'high', message: 'Static or content site without API endpoints — CORS not needed', findings: [] };
    }

    const hasServerFile = tree.some(p => SERVER_FILE_RX.test(p) && isRelevantPath(p));
    if (hasServerFile) {
      return { checkId, status: 'check-it', confidence: 'low', message: 'Server-like files detected without visible CORS configuration', findings: [{ file: 'unknown', issue: 'Server files present; verify if cross-origin requests need CORS' }] };
    }

    return { checkId, status: 'not-applicable', confidence: 'high', message: 'No server or API endpoints detected — CORS not needed', findings: [] };
  } catch (err) {
    return { checkId, status: 'not-applicable', confidence: 'low', message: `Error during CORS check: ${err.message}`, findings: [{ file: 'unknown', issue: `Error: ${err.message}` }] };
  }
}
